using Test
using InteractiveUtils: code_llvm
using PackedParselets

const PP = PackedParselets

# --- Test harness ---

# Abstract base type for test types (not AbstractIdentifier)
abstract type AbstractPacked end

# Post-processing: generates parse/tryparse using ArgumentError.
# tobytes, print, and string are already generated by assemble_type.
function test_finalize!(block::Expr, state::PP.ParserState, name::Symbol)
    ename = esc(name)
    errmsgs = Tuple(state.errconsts)
    push!(block.args,
        :(function $(GlobalRef(Base, :parse))(::Type{$ename}, id::AbstractString)
              result, pos = $(GlobalRef(PP, :parsebytes))($ename, codeunits(id))
              if result isa $ename
                  pos > ncodeunits(id) || throw(ArgumentError("Unparsed trailing content in " * repr(id)))
                  result
              else
                  throw(ArgumentError(@inbounds $errmsgs[result]))
              end
          end))
    push!(block.args,
        :(function $(GlobalRef(Base, :tryparse))(::Type{$ename}, id::AbstractString)
              result, pos = $(GlobalRef(PP, :parsebytes))($ename, codeunits(id))
              result isa $ename && pos > ncodeunits(id) ? result : nothing
          end))
end

# Strip Expr(:escape, x) wrappers inserted by esc() — needed when
# eval'ing generated code directly instead of macro-expanding it.
function strip_esc(expr::Expr)
    if Meta.isexpr(expr, :escape, 1)
        return strip_esc(expr.args[1])
    end
    Expr(expr.head, map(strip_esc, expr.args)...)
end
strip_esc(x) = x

# For eval: strips esc wrappers that are only meaningful in macro context.
function packed_deftype(mod::Module, name::Symbol, pattern;
                        segments::NamedTuple = PP.CORE_SEGMENTS, kwargs...)
    block, state = PP.maketype(segments, mod, name, pattern;
                               supertype=AbstractPacked, kwargs...)
    test_finalize!(block, state, name)
    strip_esc(block)
end

# For macro expansion: esc wrappers are needed for hygiene.
macro defpacked(name, pattern)
    block, state = PP.maketype(PP.CORE_SEGMENTS, __module__, name, pattern;
                               supertype=AbstractPacked)
    test_finalize!(block, state, name)
    block
end

# --- AST complexity analysis utilities ---

# Clean raw @macroexpand output: strip hygiene wrappers, line numbers,
# gensym mangling, and GlobalRefs to produce a readable AST.
function exprclean!(expr::Expr)
    if expr.head == :.
        return last(expr.args).value
    elseif expr.head == :toplevel
        return exprclean!(Expr(:block, expr.args...))
    elseif expr.head == Symbol("hygienic-scope")
        return exprclean!(first(expr.args))
    elseif expr.head == :escape
        return if first(expr.args) isa Expr
            exprclean!(first(expr.args))
        else
            first(expr.args)
        end
    end
    delat = Int[]
    for (i, arg) in enumerate(expr.args)
        if arg isa Symbol && '#' in String(arg)
            segs = split(String(arg), '#')
            expr.args[i] = if all(isdigit, last(segs)) && length(segs) > 1
                Symbol(segs[end-1] * '_' * segs[end])
            else
                Symbol(last(split(String(arg), '#')))
            end
        elseif arg isa Expr
            expr.args[i] = exprclean!(arg)
        elseif arg isa GlobalRef
            expr.args[i] = arg.name
        elseif arg isa LineNumberNode
            if expr.head === :macrocall
                expr.args[i] = LineNumberNode(0, Symbol(""))
            else
                push!(delat, i)
            end
        end
    end
    deleteat!(expr.args, delat)
    expr
end

# Walk a cleaned AST to find the parsebytes function body.
function extract_parsebytes(expr::Expr)
    if expr.head == :function
        sig = expr.args[1]
        if sig isa Expr && any(a -> a === :parsebytes, sig.args)
            return expr.args[2]
        end
    end
    for a in expr.args
        a isa Expr || continue
        r = extract_parsebytes(a)
        !isnothing(r) && return r
    end
    nothing
end

# --- Control-flow-aware AST cost walker ---

is_goto_expr(e) = e isa Expr && e.head === :macrocall && !isempty(e.args) &&
    e.args[1] in (Symbol("@goto"), GlobalRef(Base, Symbol("@goto")))
is_label_expr(e) = e isa Expr && e.head === :macrocall && !isempty(e.args) &&
    e.args[1] in (Symbol("@label"), GlobalRef(Base, Symbol("@label")))
goto_label_sym(e) = e.args[end]

const LabelCtx = Dict{Symbol, @NamedTuple{stmts::AbstractVector, pos::Int}}

function walk_expr(cost_fn, expr; labels::LabelCtx=LabelCtx(), cont=() -> (0, 0))
    expr isa Expr || return cont()
    if is_goto_expr(expr)
        sym = goto_label_sym(expr)
        target = get(labels, sym, nothing)
        if !isnothing(target)
            return walk_stmts(cost_fn, target.stmts, target.pos + 1, labels)
        end
        return cont()
    end
    is_label_expr(expr) && return cont()
    n = cost_fn(expr)
    clo, chi = if expr.head in (:if, :elseif) && !(expr.args[1] isa Bool)
        walk_branch(cost_fn, expr, labels, cont)
    elseif expr.head in (:&&, :||)
        walk_shortcircuit(cost_fn, expr, labels, cont)
    elseif expr.head === :block
        walk_block(cost_fn, expr.args, labels, cont)
    else
        walk_children(cost_fn, expr.args, labels, cont)
    end
    (n + clo, n + chi)
end

function walk_children(cost_fn, args, labels, cont)
    lo, hi = 0, 0
    for a in args
        alo, ahi = walk_expr(cost_fn, a; labels, cont=() -> (0, 0))
        lo += alo; hi += ahi
    end
    clo, chi = cont()
    (lo + clo, hi + chi)
end

function walk_branch(cost_fn, expr, labels, cont)
    cond_lo, cond_hi = walk_expr(cost_fn, expr.args[1]; labels)
    then_lo, then_hi = walk_expr(cost_fn, expr.args[2]; labels, cont)
    else_lo, else_hi = if length(expr.args) >= 3
        walk_expr(cost_fn, expr.args[3]; labels, cont)
    else
        cont()
    end
    (cond_lo + min(then_lo, else_lo),
     cond_hi + max(then_hi, else_hi))
end

function walk_shortcircuit(cost_fn, expr, labels, cont)
    left_lo, left_hi = walk_expr(cost_fn, expr.args[1]; labels)
    skip_lo, skip_hi = cont()
    right_lo, right_hi = walk_expr(cost_fn, expr.args[2]; labels, cont)
    (left_lo + min(skip_lo, right_lo),
     left_hi + max(skip_hi, right_hi))
end

function walk_block(cost_fn, stmts, labels, cont)
    local_labels = copy(labels)
    for (i, s) in enumerate(stmts)
        if is_label_expr(s)
            local_labels[goto_label_sym(s)] = (; stmts, pos=i)
        end
    end
    walk_stmts(cost_fn, stmts, 1, local_labels, cont)
end

function walk_stmts(cost_fn, stmts, start::Int, labels::LabelCtx, cont=() -> (0, 0))
    start > length(stmts) && return cont()
    rest = () -> walk_stmts(cost_fn, stmts, start + 1, labels, cont)
    walk_expr(cost_fn, stmts[start]; labels, cont=rest)
end

function walk_total(cost_fn, expr)
    expr isa Expr || return 0
    n = cost_fn(expr)
    for a in expr.args
        n += walk_total(cost_fn, a)
    end
    n
end

function count_branches(expr)
    cost_fn = e -> begin
        if e.head in (:if, :elseif)
            Int(!(e.args[1] isa Bool))
        elseif e.head in (:&&, :||)
            Int(!(e.args[1] isa Bool))
        else
            0
        end
    end
    lo, hi = walk_expr(cost_fn, expr)
    tot = walk_total(cost_fn, expr)
    (lo, hi, tot)
end

const COUNTED_OPS = Set{Symbol}([
    :+, :-, :*, :div, :%, :&, :|, :xor, :⊻,
    :<<, :>>, :>>>,
    :or_int, :shl_int, :lshr_int, :zext_int, :trunc_int, :bitcast, :ult_int,
])

const COMPOUND_ASSIGN_OPS = Dict{Symbol, Symbol}(
    :+= => :+, :-= => :-, :*= => :*,
    :<<= => :<<, :>>= => :>>, :>>>= => :>>>,
    :&= => :&, :|= => :|, :⊻= => :⊻,
)

function count_ops(expr)
    walk_expr(expr) do e
        n = 0
        if e.head == :call && length(e.args) >= 1
            op = first(e.args)
            if op isa Symbol && op in COUNTED_OPS
                n += 1
            end
        end
        implicit_op = get(COMPOUND_ASSIGN_OPS, e.head, nothing)
        if !isnothing(implicit_op) && implicit_op in COUNTED_OPS
            n += 1
        end
        n
    end
end

function parsebytes_complexity(defpacked_expr::Expr)
    expanded = macroexpand(@__MODULE__, defpacked_expr)
    cleaned = exprclean!(expanded)
    body = extract_parsebytes(cleaned)
    isnothing(body) && return nothing
    blo, bhi, btot = count_branches(body)
    olo, ohi = count_ops(body)
    (; branches=blo:bhi, branch_total=btot, ops=olo:ohi)
end

function check_roundtrips(T, inputs)
    for input in inputs
        id = parse(T, input)
        @test parse(T, string(id)) == id
    end
end

"""
    @test_neverthrow f(arg1, ::Type, ...)

Test that the LLVM IR for the given method signature contains no `throw` calls
(bounds errors, type errors, etc). Arguments can be `::Type` annotations to
specify types directly, or value expressions (resolved via `ttypeof` at expansion time).
"""
macro test_neverthrow(expr)
    Meta.isexpr(expr, :call) || error("@test_neverthrow expects a call expression, got: $expr")
    func = expr.args[1]
    argtypes = map(expr.args[2:end]) do arg
        if Meta.isexpr(arg, :(::), 1)
            esc(arg.args[1])
        else
            :(ttypeof($(esc(arg))))
        end
    end
    typetup = Expr(:curly, :Tuple, argtypes...)
    quote
        let ir = sprint(code_llvm, $(esc(func)), $typetup; context=:debuginfo => :none)
            throws = filter(contains("ijl_throw"), split(ir, '\n'))
            @test isempty(throws)
        end
    end
end
ttypeof(::Type{T}) where {T} = Type{T}
ttypeof(x) = typeof(x)

# --- Tests ---

@testset "PackedParselets" begin

# ── Core segment tests (from packed.jl) ──

@testset "literal + digits" begin
    @defpacked LitDigit ("AB", :val(digits(4, pad=4)))
    @test parse(LitDigit, "AB0042") isa LitDigit
    x = parse(LitDigit, "AB0042")
    @test x.val == 42
    @test string(x) == "AB0042"
    @test tryparse(LitDigit, "AB0042") == x
    @test tryparse(LitDigit, "XX0042") === nothing
    @test tryparse(LitDigit, "AB") === nothing
    # Round-trip
    for v in (0, 1, 9999)
        @test parse(LitDigit, string(LitDigit(v))) == LitDigit(v)
    end
    # Type properties
    @test LitDigit <: AbstractPacked
    @test isprimitivetype(LitDigit)
    @test PP.parsebounds(LitDigit) == (6, 6)
    @test PP.printbounds(LitDigit) == (6, 6)
end

@testset "choice" begin
    @defpacked Colour (choice("red", "green", "blue"))
    @test parse(Colour, "red") isa Colour
    @test parse(Colour, "green") isa Colour
    @test parse(Colour, "blue") isa Colour
    @test tryparse(Colour, "yellow") === nothing
    for c in ("red", "green", "blue")
        @test string(parse(Colour, c)) == c
    end
end

@testset "choice with field" begin
    @defpacked Flagged (:kind(choice("alpha", "beta", "gamma")),
                        "-", :num(digits(3, pad=3)))
    x = parse(Flagged, "beta-007")
    @test x.kind == :beta
    @test x.num == 7
    @test string(x) == "beta-007"
    @test propertynames(x) == (:kind, :num)
end

@testset "skip" begin
    @defpacked Skipped (skip("http://", "https://"), :val(digits(5)))
    @test parse(Skipped, "12345").val == 12345
    @test parse(Skipped, "http://12345").val == 12345
    @test parse(Skipped, "https://12345").val == 12345
    @test string(parse(Skipped, "http://99999")) == "99999"
end

@testset "letters" begin
    @defpacked Code3 (:code(letters(3)))
    x = parse(Code3, "ABC")
    @test x.code == "ABC"
    @test string(x) == "ABC"
    # Case folding (default casefold=true)
    @test parse(Code3, "abc") == parse(Code3, "ABC")
end

@testset "alphnum" begin
    @defpacked AlphaNum4 (:tag(alphnum(4)))
    x = parse(AlphaNum4, "AB12")
    @test string(x) == "AB12"
    @test parse(AlphaNum4, "ab12") == x
end

@testset "hex" begin
    @defpacked HexId (:h(hex(4)))
    x = parse(HexId, "DEAD")
    @test string(x) == "DEAD"
    @test parse(HexId, "dead") == x
    @test tryparse(HexId, "GHIJ") === nothing
end

@testset "charset" begin
    @defpacked BinId (:bits(charset(8, '0':'1')))
    x = parse(BinId, "10110010")
    @test string(x) == "10110010"
    @test tryparse(BinId, "10110020") === nothing
end

@testset "optional" begin
    @defpacked OptSuffix (:num(digits(4, pad=4)),
                          optional(".", :ext(digits(max=255))))
    # Without optional
    x = parse(OptSuffix, "0042")
    @test x.num == 42
    @test x.ext === nothing
    @test string(x) == "0042"
    # With optional
    y = parse(OptSuffix, "0042.7")
    @test y.num == 42
    @test y.ext == 7
    @test string(y) == "0042.7"
    # Round-trip
    @test parse(OptSuffix, string(x)) == x
    @test parse(OptSuffix, string(y)) == y
end

@testset "nested optional" begin
    @defpacked NestedOpt (:a(digits(3, pad=3)),
                          optional(".", :b(digits(max=99)),
                                   optional(".", :c(digits(max=99)))))
    x = parse(NestedOpt, "042")
    @test x.a == 42 && x.b === nothing && x.c === nothing
    y = parse(NestedOpt, "042.5")
    @test y.a == 42 && y.b == 5 && y.c === nothing
    z = parse(NestedOpt, "042.5.10")
    @test z.a == 42 && z.b == 5 && z.c == 10
    for v in (x, y, z)
        @test parse(NestedOpt, string(v)) == v
    end
end

@testset "constructor" begin
    @defpacked Constructed (:a(digits(3, pad=3)), "-",
                            :b(choice("x", "y", "z")))
    x = Constructed(42, :y)
    @test x.a == 42
    @test x.b == :y
    @test string(x) == "042-y"
    @test parse(Constructed, "042-y") == x
end

@testset "optional constructor" begin
    @defpacked OptCons (:id(digits(4, pad=4)),
                        optional("v", :ver(digits(max=255))))
    x = OptCons(5, 3)
    @test x.id == 5 && x.ver == 3
    @test string(x) == "0005v3"
    y = OptCons(5, nothing)
    @test y.id == 5 && y.ver === nothing
    @test string(y) == "0005"
end

@testset "isless" begin
    @defpacked Ordered (:n(digits(4)))
    a = parse(Ordered, "0100")
    b = parse(Ordered, "0200")
    @test a < b
    @test !(b < a)
    @test !(a < a)
end

@testset "segments introspection" begin
    @defpacked SegInspect ("X", :val(digits(3, pad=3)))
    schema = PP.segments(SegInspect)
    @test length(schema) >= 1
    @test any(s -> s.label == :val, schema)
    x = parse(SegInspect, "X042")
    vals = PP.segments(x)
    @test length(vals) >= 1
end

@testset "variable-width digits" begin
    @defpacked VarDig (:n(digits(1:5)))
    for v in (0, 9, 99, 999, 9999, 99999)
        x = VarDig(v)
        @test parse(VarDig, string(x)) == x
    end
    @test tryparse(VarDig, "100000") === nothing  # exceeds 5 digits
end

@testset "show forms" begin
    @defpacked ShowTest (:id(digits(3, pad=3)))
    x = ShowTest(42)
    # Constructor form (no :limit)
    @test sprint(show, x) == "ShowTest(42)"
    # Compact form (:limit) uses print(io, id)
    @test sprint(show, x; context=IOContext(stdout, :limit => true)) == "ShowTest:042"
    # With typeinfo suppressed
    @test sprint(show, x; context=IOContext(stdout, :limit => true, :typeinfo => ShowTest)) == "042"
end

@testset "print and string" begin
    @defpacked PrintTest (:a(digits(2, pad=2)), "-", :b(letters(3)))
    x = parse(PrintTest, "42-ABC")
    @test string(x) == "42-ABC"
    @test sprint(print, x) == "42-ABC"
end

eval(packed_deftype(@__MODULE__, :EmbInner, :(:x(digits(2, pad=2)))))
eval(packed_deftype(@__MODULE__, :EmbOuter,
    :(("E", :inner(embed(EmbInner)), "-", :extra(digits(2, pad=2))))))
@testset "embed" begin
    x = parse(EmbOuter, "E05-10")
    @test x.inner isa EmbInner
    @test x.inner.x == 5
    @test x.extra == 10
    @test string(x) == "E05-10"
    @test parse(EmbOuter, string(x)) == x
end

@testset "case folding disabled" begin
    expr = packed_deftype(@__MODULE__, :CaseSensitive,
                          :((choice(casefold=false, "Abc", "DEF")));
                          casefold=false)
    eval(expr)
    @test tryparse(CaseSensitive, "Abc") isa CaseSensitive
    @test tryparse(CaseSensitive, "DEF") isa CaseSensitive
    @test tryparse(CaseSensitive, "abc") === nothing
    @test tryparse(CaseSensitive, "def") === nothing
end

# --- Extension API: custom timestamp segment ---

@testset "custom segment (timestamp)" begin
    function compile_timestamp(state::PP.ParserState, nctx::PP.NodeCtx, ::PP.PatternExprs,
                               ::PP.SegmentDef, args::Vector{Any})
        isempty(args) || throw(ArgumentError("timestamp takes no arguments"))
        option = get(nctx, :optional, nothing)
        claims = PP.unclaimed_sentinel(nctx)
        presbits = claims ? 1 : 0
        nbits = 24 + presbits
        fieldvar = get(nctx, :fieldvar, gensym("timestamp"))
        nbits_pos = state.bits + nbits
        yvar = gensym("year"); mvar = gensym("month"); dvar = gensym("day")
        tvar = gensym("tsval")
        errmsg = PP.register_errmsg!(state, "Invalid timestamp")
        opt_label = get(nctx, :opt_label, nothing)
        notfound = if isnothing(option)
            [:(return ($errmsg, pos))]
        else
            [PP.opt_fail_expr(option, opt_label)]
        end
        ylen = gensym("ylen"); mlen = gensym("mlen"); dlen = gensym("dlen")
        parse_exprs = PP.ExprVarLine[
            :(($ylen, $yvar) = PP.parseint(UInt32, idbytes, pos, 10, 4)),
            :($ylen == 4 || $(notfound...)),
            :(($mlen, $mvar) = PP.parseint(UInt32, idbytes, pos + 4, 10, 2)),
            :($mlen == 2 || $(notfound...)),
            :(($dlen, $dvar) = PP.parseint(UInt32, idbytes, pos + 6, 10, 2)),
            :($dlen == 2 || $(notfound...)),
            :($tvar = UInt32(($yvar - 2000) * 10000 + $mvar * 100 + $dvar)),
            PP.emit_pack(state, UInt32, tvar, nbits_pos - presbits)]
        if claims
            push!(parse_exprs, PP.emit_pack(state, Bool, true, nbits_pos))
        end
        push!(parse_exprs, :(pos += 8))
        fextract = :($fieldvar = $(PP.emit_extract(state, nbits_pos - presbits, 24)))
        print_exprs = PP.ExprVarLine[
            :(print(io, string(div($fieldvar, 10000) + 2000, pad=4))),
            :(print(io, string(div($fieldvar % 10000, 100), pad=2))),
            :(print(io, string($fieldvar % 100, pad=2)))]
        argvar = gensym("arg_ts")
        argconv = gensym("arg_ts_u32")
        impart_body = Any[:($argconv = $argvar % UInt32),
                          PP.emit_pack(state, UInt32, argconv, nbits_pos - presbits)]
        if presbits > 0
            push!(impart_body, PP.emit_pack(state, Bool, true, nbits_pos))
        end
        sentinel = if claims; PP.SentinelSpec((0, presbits)) else nothing end
        PP.value_segment_output(;
            bounds=PP.SegmentBounds(8:8, 8:8, nbits, sentinel),
            fieldvar, desc="timestamp (YYYYMMDD)", shortform="YYYYMMDD",
            argvar, base_argtype=:Integer, option,
            parse=parse_exprs,
            extract_setup=PP.ExprVarLine[fextract], extract_value=fieldvar,
            impart_body, print=print_exprs)
    end

    function finalize_timestamp!(block::Expr, state::PP.ParserState, name::Symbol)
        ts_output = let idx = findfirst(p -> first(p) === :timestamp, state.segment_outputs)
            isnothing(idx) ? nothing : last(state.segment_outputs[idx])
        end
        isnothing(ts_output) && return
        ename = esc(name)
        extract_exprs = copy(ts_output.codegen.extract)
        PP.implement_casting!(state, extract_exprs)
        val_expr = extract_exprs[end]
        setup = extract_exprs[1:end-1]
        push!(block.args,
            :(function dateof(id::$ename)
                  $(setup...)
                  v = $val_expr
                  (div(v, 10000) + 2000, div(v % 10000, 100), v % 100)
              end))
    end

    TIMESTAMP_SEGMENTS = merge(PP.CORE_SEGMENTS, (timestamp = PP.SegmentDef(:timestamp, compile_timestamp, ()),))

    ts_block, ts_state = PP.maketype(TIMESTAMP_SEGMENTS, @__MODULE__, :Event,
        :(("EVT-", :date(timestamp()), "-", :id(digits(3, pad=3))));
        supertype=AbstractPacked)
    test_finalize!(ts_block, ts_state, :Event)
    finalize_timestamp!(ts_block, ts_state, :Event)
    eval(strip_esc(ts_block))

    @test Event <: AbstractPacked
    @test isprimitivetype(Event)

    @testset "parsing" begin
        x = parse(Event, "EVT-20250615-042")
        @test x isa Event
        @test x.id == 42
        @test tryparse(Event, "EVT-20250615-042") == x
        @test tryparse(Event, "EVT-BAD-042") === nothing
        @test tryparse(Event, "XYZ-20250615-042") === nothing
    end

    @testset "round-trip" begin
        x = parse(Event, "EVT-20250615-042")
        @test string(x) == "EVT-20250615-042"
        @test parse(Event, string(x)) == x
    end

    @testset "constructor" begin
        x = Event(250615, 42)
        @test string(x) == "EVT-20250615-042"
    end

    @testset "dateof finalize hook" begin
        x = parse(Event, "EVT-20250615-042")
        @test dateof(x) == (2025, 6, 15)
        y = parse(Event, "EVT-20001231-001")
        @test dateof(y) == (2000, 12, 31)
    end

    @testset "segments" begin
        schema = PP.segments(Event)
        @test length(schema) >= 2
        ts_seg = first(s for s in schema if s.kind == :timestamp)
        @test ts_seg.desc == "timestamp (YYYYMMDD)"
    end

    @testset "optional timestamp" begin
        ts_opt_block, ts_opt_state = PP.maketype(TIMESTAMP_SEGMENTS, @__MODULE__, :MaybeEvent,
            :((:id(digits(3, pad=3)), optional("-", :date(timestamp()))));
            supertype=AbstractPacked)
        test_finalize!(ts_opt_block, ts_opt_state, :MaybeEvent)
        finalize_timestamp!(ts_opt_block, ts_opt_state, :MaybeEvent)
        eval(strip_esc(ts_opt_block))
        x = parse(MaybeEvent, "042")
        @test x.id == 42
        @test x.date === nothing
        y = parse(MaybeEvent, "042-20250101")
        @test y.id == 42
        @test y.date isa Integer
        @test string(x) == "042"
        @test string(y) == "042-20250101"
        @test parse(MaybeEvent, string(x)) == x
        @test parse(MaybeEvent, string(y)) == y
    end
end

# --- No post-processing ---

@testset "bare maketype (no post-processing)" begin
    block, state = PP.maketype(PP.CORE_SEGMENTS, @__MODULE__, :Bare,
                               :(:val(digits(3, pad=3)));
                               supertype=AbstractPacked)
    eval(strip_esc(block))
    @test Bare <: AbstractPacked
    @test PP.parsebounds(Bare) == (3, 3)
    # parsebytes works
    result, pos = PP.parsebytes(Bare, codeunits("042"))
    @test result isa Bare
    @test pos == 4
    @test result.val == 42
    # Constructor works
    @test Bare(99).val == 99
    # string works (generated by assemble_type)
    @test string(Bare(99)) == "099"
    # No parse/tryparse defined (no post-processing was applied)
    @test_throws MethodError parse(Bare, "042")
end

# --- Round-trip invariant across all test types ---

@testset "round-trip invariant" begin
    samples = [
        LitDigit(0), LitDigit(42), LitDigit(9999),
        parse(Colour, "red"), parse(Colour, "green"), parse(Colour, "blue"),
        Flagged(:alpha, 7), Flagged(:gamma, 999),
        parse(Skipped, "12345"), parse(Skipped, "http://99999"),
        parse(Code3, "ABC"), parse(Code3, "XYZ"),
        parse(AlphaNum4, "AB12"), parse(AlphaNum4, "ZZ99"),
        parse(HexId, "DEAD"), parse(HexId, "00FF"),
        parse(BinId, "10110010"), parse(BinId, "00000000"),
        OptSuffix(42, nothing), OptSuffix(42, 7),
        NestedOpt(42, nothing, nothing), NestedOpt(42, 5, 10),
        Constructed(42, :y), Constructed(0, :z),
        OptCons(5, 3), OptCons(5, nothing),
        parse(Ordered, "0100"), parse(Ordered, "9999"),
    ]
    for x in samples
        T = typeof(x)
        @test parse(T, string(x)) == x
    end
end

# ── Migrated segment tests from defid.jl ──

    @testset "digits" begin
        @testset "SimpleNum" begin
            iddef = :(@defpacked SimpleNum ("SN", :id(digits(max=9999, pad=4))))
            @test parsebytes_complexity(iddef) == (branches=5:9, branch_total=9, ops=24:49)
            eval(iddef)
            # Parsing
            @test parse(SimpleNum, "SN42") isa SimpleNum
            @test parse(SimpleNum, "SN42").id == 42
            @test parse(SimpleNum, "SN0042").id == 42
            # Properties
            @test propertynames(parse(SimpleNum, "SN1")) == (:id,)
            @test parse(SimpleNum, "SN42").id isa Integer
            @test_throws Exception parse(SimpleNum, "SN1").nonexistent
            # String
            @test string(parse(SimpleNum, "SN42")) == "SN0042"
            @test string(parse(SimpleNum, "SN0")) == "SN0000"
            @test string(parse(SimpleNum, "SN9999")) == "SN9999"
            # Equality
            @test parse(SimpleNum, "SN42") == parse(SimpleNum, "SN0042")
            @test hash(parse(SimpleNum, "SN42")) == hash(parse(SimpleNum, "SN0042"))
            @test parse(SimpleNum, "SN1") != parse(SimpleNum, "SN2")
            # Comparison
            a, b, c = parse.(SimpleNum, ("SN1", "SN2", "SN9999"))
            @test a < b < c
            @test sort([c, a, b]) == [a, b, c]
            # Errors
            @test tryparse(SimpleNum, "") === nothing
            @test tryparse(SimpleNum, "WRONG42") === nothing
            @test tryparse(SimpleNum, "SN") === nothing
            @test tryparse(SimpleNum, "SN99999") === nothing
            @test tryparse(SimpleNum, "SN42EXTRA") === nothing
            @test_throws ArgumentError parse(SimpleNum, "")
            @test_throws ArgumentError parse(SimpleNum, "WRONG42")
            @test_throws ArgumentError parse(SimpleNum, "SN42EXTRA")
            # Edge cases
            @test parse(SimpleNum, "SN0").id == 0
            @test string(parse(SimpleNum, "SN0")) == "SN0000"
            @test parse(SimpleNum, "SN9999").id == 9999
            @test tryparse(SimpleNum, "SN10000") === nothing
            # Round-trips
            check_roundtrips(SimpleNum, ("SN0", "SN1", "SN9999"))
            @test_neverthrow PP.parsebytes(SimpleNum, ::Vector{UInt8})
        end

        @testset "BareDigits" begin
            iddef = :(@defpacked BareDigits :id(digits(5)))
            @test parsebytes_complexity(iddef) == (branches=2:2, branch_total=2, ops=27:27)
            eval(iddef)
            @test sizeof(BareDigits) >= 1
            # Parsing
            @test parse(BareDigits, "12345") isa BareDigits
            @test parse(BareDigits, "12345").id == 12345
            # Single-character digit strings
            for d in 0:9
                id = parse(BareDigits, "0000$d")
                @test id.id == d
            end
            # Round-trips
            check_roundtrips(BareDigits, ("00001", "99999"))
            @test_neverthrow PP.parsebytes(BareDigits, ::Vector{UInt8})
        end

        @testset "VarDigits" begin
            iddef = :(@defpacked VarDigits :id(digits(1:5)))
            @test parsebytes_complexity(iddef) == (branches=5:8, branch_total=8, ops=25:55)
            eval(iddef)
            @test sizeof(VarDigits) >= 1
            # Variable width: accepts 1 to 5 digits
            @test parse(VarDigits, "1").id == 1
            @test parse(VarDigits, "42").id == 42
            @test parse(VarDigits, "12345").id == 12345
            # Rejects 0 or >5 digits
            @test tryparse(VarDigits, "") === nothing
            @test tryparse(VarDigits, "123456") === nothing
            # String uses minimal width (no zero-padding)
            @test string(parse(VarDigits, "1")) == "1"
            @test string(parse(VarDigits, "00042")) == "42"
            # Round-trips
            check_roundtrips(VarDigits, ("1", "42", "99999"))
            @test_neverthrow PP.parsebytes(VarDigits, ::Vector{UInt8})
        end

        @testset "VarHexDigits" begin
            iddef = :(@defpacked VarHexDigits ("0x", :id(digits(1:4, base=16))))
            @test parsebytes_complexity(iddef) == (branches=5:9, branch_total=9, ops=29:75)
            eval(iddef)
            # Variable width: accepts 1 to 4 hex digits
            @test parse(VarHexDigits, "0xf").id == 0xf
            @test parse(VarHexDigits, "0xff").id == 0xff
            @test parse(VarHexDigits, "0xffff").id == 0xffff
            # Rejects empty or >4 hex digits
            @test tryparse(VarHexDigits, "0x") === nothing
            @test tryparse(VarHexDigits, "0xfffff") === nothing
            # String uses minimal width
            @test string(parse(VarHexDigits, "0xff")) == "0xff"
            @test string(parse(VarHexDigits, "0x00ff")) == "0xff"
            # Round-trips
            check_roundtrips(VarHexDigits, ("0xf", "0xff", "0xffff"))
            @test_neverthrow PP.parsebytes(VarHexDigits, ::Vector{UInt8})
        end

        @testset "ZFilled" begin
            iddef = :(@defpacked ZFilled ("ZF-", :id(digits(4:4))))
            @test parsebytes_complexity(iddef) == (branches=3:3, branch_total=3, ops=20:20)
            eval(iddef)
            # Parsing
            @test parse(ZFilled, "ZF-0042") isa ZFilled
            @test parse(ZFilled, "ZF-0042").id == 42
            # Must be exactly 4 digits
            @test tryparse(ZFilled, "ZF-42") === nothing
            # String
            @test string(parse(ZFilled, "ZF-0001")) == "ZF-0001"
            @test string(parse(ZFilled, "ZF-0000")) == "ZF-0000"
            # Errors
            @test tryparse(ZFilled, "ZF-12") === nothing
            # Round-trips
            check_roundtrips(ZFilled, ("ZF-0000", "ZF-0042", "ZF-9999"))
            @test_neverthrow PP.parsebytes(ZFilled, ::Vector{UInt8})
        end

        @testset "HexId" begin
            iddef = :(@defpacked HexId2 ("0x", :id(digits(4, base=16))))
            @test parsebytes_complexity(iddef) == (branches=3:3, branch_total=3, ops=32:32)
            eval(iddef)
            # Parsing
            @test parse(HexId2, "0x00ff") isa HexId2
            @test parse(HexId2, "0x00ff").id == 0xff
            # Must be exactly 4 hex digits
            @test tryparse(HexId2, "0xff") === nothing
            # String
            sc = string(parse(HexId2, "0x00ff"))
            @test occursin("00ff", sc)
            @test startswith(sc, "0x")
            # Errors
            @test tryparse(HexId2, "0xGGGG") === nothing
