            eval(iddef)
            id = parse(LettersFolded, "R-HSA-42")
            @test id.code == "HSA"
            @test id.id == 42
            @test parse(LettersFolded, "R-hsa-42") == id
            check_roundtrips(LettersFolded, ("R-HSA-42", "R-ABC-0"))
