        @test parse(OptCharset, "42.00") != parse(OptCharset, "42")
        @test parse(OptCharset, "42.AA").tag == "AA"
        @test parse(OptCharset, "42.ZZ").tag == "ZZ"
        @test parse(OptCharset, "42.00").tag == "00"
