        @test_neverthrow PP.parsebytes(OptCharset, ::Vector{UInt8})
    end
    @testset "CharsetNoCasefold" begin
        iddef = :(@defpacked CharsetNoCasefold :code(charset(3, 'A':'Z', 'a':'z', casefold=false)))
        @test parsebytes_complexity(iddef) == (branches=2:2, branch_total=2, ops=7:7)
        eval(iddef)
        a = parse(CharsetNoCasefold, "ABc")
        b = parse(CharsetNoCasefold, "abC")
        @test a != b
        @test a.code == "ABc"
        @test b.code == "abC"
        @test parse(CharsetNoCasefold, "AAA").code == "AAA"
        @test parse(CharsetNoCasefold, "ZZZ").code == "ZZZ"
        @test parse(CharsetNoCasefold, "aaa").code == "aaa"
        @test parse(CharsetNoCasefold, "zzz").code == "zzz"
        @test tryparse(CharsetNoCasefold, "@@@") === nothing
        @test tryparse(CharsetNoCasefold, "[[[") === nothing
        @test tryparse(CharsetNoCasefold, "```") === nothing
        @test tryparse(CharsetNoCasefold, "{{{") === nothing
        @test tryparse(CharsetNoCasefold, "123") === nothing
        check_roundtrips(CharsetNoCasefold, ("ABc", "abC", "AAA", "zzz"))
        @test_neverthrow PP.parsebytes(CharsetNoCasefold, ::Vector{UInt8})
    end
    @testset "CharsetWithLiteral" begin
        iddef = :(@defpacked CharsetWithLiteral ("X-",
                   :hash(charset(4, '0':'9', 'A':'F', casefold=true)),
                   "-", :ver(digits(max=99))))
        @test parsebytes_complexity(iddef) == (branches=5:5, branch_total=5, ops=39:39)
        eval(iddef)
        id = parse(CharsetWithLiteral, "X-A1B2-7")
        @test id.hash == "A1B2"
        @test id.ver == 7
        @test parse(CharsetWithLiteral, "X-a1b2-7") == id
        @test parse(CharsetWithLiteral, "X-0000-0").hash == "0000"
        @test parse(CharsetWithLiteral, "X-9999-0").hash == "9999"
        @test parse(CharsetWithLiteral, "X-AAAA-0").hash == "AAAA"
        @test parse(CharsetWithLiteral, "X-FFFF-0").hash == "FFFF"
        @test tryparse(CharsetWithLiteral, "X-GHIJ-1") === nothing
        @test tryparse(CharsetWithLiteral, "X-////-1") === nothing
        check_roundtrips(CharsetWithLiteral, ("X-0000-0", "X-A1B2-7", "X-FFFF-99"))
        @test_neverthrow PP.parsebytes(CharsetWithLiteral, ::Vector{UInt8})
    end
end # charset

@testset "embed" begin
    # --- Inner types at various bit widths ---
    eval(:(@defpacked EmbTiny :id(digits(max=3))))
    eval(:(@defpacked Emb8 ("X", :id(digits(max=255)))))
    eval(:(@defpacked Emb16 ("P", :id(digits(max=9999, pad=4)))))
    @testset "single embed <8 bits" begin
        iddef = :(@defpacked EmbedTinyOuter ("T-", :inner(embed(EmbTiny)), "-", :extra(digits(max=99))))
        @test parsebytes_complexity(iddef) == (branches=5:5, branch_total=5, ops=41:41)
        eval(iddef)
        @test sizeof(EmbedTinyOuter) >= 1
        id = parse(EmbedTinyOuter, "T-3-42")
        @test id.inner isa EmbTiny
        @test id.inner.id == 3
        @test id.extra == 42
        @test parse(EmbedTinyOuter, "T-0-0").inner.id == 0
        @test parse(EmbedTinyOuter, "T-0-0").extra == 0
        @test propertynames(parse(EmbedTinyOuter, "T-1-2")) == (:inner, :extra)
        @test string(parse(EmbedTinyOuter, "T-3-42")) == "T-3-42"
        @test parse(EmbedTinyOuter, "T-2-5") == parse(EmbedTinyOuter, "T-2-5")
        @test parse(EmbedTinyOuter, "T-2-5") != parse(EmbedTinyOuter, "T-2-6")
        @test parse(EmbedTinyOuter, "T-2-5") != parse(EmbedTinyOuter, "T-3-5")
        @test hash(parse(EmbedTinyOuter, "T-1-1")) == hash(parse(EmbedTinyOuter, "T-1-1"))
        @test tryparse(EmbedTinyOuter, "") === nothing
        @test tryparse(EmbedTinyOuter, "T-") === nothing
        @test tryparse(EmbedTinyOuter, "T-4-1") === nothing
        @test tryparse(EmbedTinyOuter, "T-1-100") === nothing
        @test tryparse(EmbedTinyOuter, "T-1") === nothing
        check_roundtrips(EmbedTinyOuter, ("T-0-0", "T-3-99", "T-1-50"))
        @test_neverthrow PP.parsebytes(EmbedTinyOuter, ::Vector{UInt8})
    end
    @testset "single embed =8 bits" begin
        iddef = :(@defpacked Embed8Outer ("E-", :inner(embed(Emb8)), "-", :id(digits(max=9))))
        @test parsebytes_complexity(iddef) == (branches=6:7, branch_total=7, ops=24:24)
        eval(iddef)
        id = parse(Embed8Outer, "E-X255-9")
        @test id.inner isa Emb8
        @test id.inner.id == 255
        @test id.id == 9
        @test parse(Embed8Outer, "E-X0-0").inner.id == 0
        @test string(parse(Embed8Outer, "E-X42-7")) == "E-X42-7"
        @test parse(Embed8Outer, "E-X1-2") == parse(Embed8Outer, "E-X1-2")
        @test parse(Embed8Outer, "E-X1-2") != parse(Embed8Outer, "E-X1-3")
        @test tryparse(Embed8Outer, "E-X256-1") === nothing
        @test tryparse(Embed8Outer, "E-Y1-1") === nothing
        @test tryparse(Embed8Outer, "E-X1") === nothing
        @test tryparse(Embed8Outer, "E-X-1") === nothing
        check_roundtrips(Embed8Outer, ("E-X0-0", "E-X255-9", "E-X128-5"))
        @test_neverthrow PP.parsebytes(Embed8Outer, ::Vector{UInt8})
    end
    @testset "single embed >8 bits" begin
        iddef = :(@defpacked Embed16Outer ("R:", :inner(embed(Emb16)), "/", :tag(digits(max=99))))
        @test parsebytes_complexity(iddef) == (branches=6:7, branch_total=7, ops=45:45)
        eval(iddef)
        @test sizeof(Embed16Outer) >= 3
        id = parse(Embed16Outer, "R:P9999/42")
        @test id.inner isa Emb16
        @test id.inner.id == 9999
        @test id.tag == 42
        @test parse(Embed16Outer, "R:P0000/0").inner.id == 0
        @test string(parse(Embed16Outer, "R:P0042/7")) == "R:P0042/7"
        a = parse(Embed16Outer, "R:P0001/1")
        b = parse(Embed16Outer, "R:P0002/1")
        c = parse(Embed16Outer, "R:P0002/2")
        @test a < b
        @test b < c
        @test sort([c, a, b]) == [a, b, c]
        @test tryparse(Embed16Outer, "R:P10000/1") === nothing
        @test tryparse(Embed16Outer, "R:Q0001/1") === nothing
        @test tryparse(Embed16Outer, "R:P0001") === nothing
        check_roundtrips(Embed16Outer, ("R:P0000/0", "R:P9999/99", "R:P0042/7"))
        @test_neverthrow PP.parsebytes(Embed16Outer, ::Vector{UInt8})
    end
    @testset "multiple adjacent embeds" begin
        iddef = :(@defpacked MultiEmbed (:a(embed(Emb16)), "-", :b(embed(Emb8))))
        @test parsebytes_complexity(iddef) == (branches=4:5, branch_total=5, ops=20:20)
        eval(iddef)
        @test sizeof(MultiEmbed) >= 3
        id = parse(MultiEmbed, "P1234-X99")
        @test id.a isa Emb16
        @test id.b isa Emb8
        @test id.a.id == 1234
        @test id.b.id == 99
        id0 = parse(MultiEmbed, "P0000-X0")
        @test id0.a.id == 0
        @test id0.b.id == 0
        idmax = parse(MultiEmbed, "P9999-X255")
        @test idmax.a.id == 9999
        @test idmax.b.id == 255
        @test propertynames(parse(MultiEmbed, "P0001-X1")) == (:a, :b)
        @test string(parse(MultiEmbed, "P0042-X7")) == "P0042-X7"
        @test parse(MultiEmbed, "P1-X2") == parse(MultiEmbed, "P0001-X2")
        @test parse(MultiEmbed, "P1-X2") != parse(MultiEmbed, "P1-X3")
        @test hash(parse(MultiEmbed, "P1-X2")) == hash(parse(MultiEmbed, "P0001-X2"))
        @test tryparse(MultiEmbed, "") === nothing
        @test tryparse(MultiEmbed, "P0001") === nothing
        @test tryparse(MultiEmbed, "P0001-Y1") === nothing
        @test tryparse(MultiEmbed, "P10000-X1") === nothing
        check_roundtrips(MultiEmbed, ("P0000-X0", "P9999-X255", "P0042-X128"))
        @test_neverthrow PP.parsebytes(MultiEmbed, ::Vector{UInt8})
    end
    @testset "three adjacent embeds (tiny + 16 + 8)" begin
        iddef = :(@defpacked TripleEmbed (:x(embed(EmbTiny)), ".", :y(embed(Emb16)), ".", :z(embed(Emb8))))
        @test parsebytes_complexity(iddef) == (branches=6:7, branch_total=7, ops=29:29)
        eval(iddef)
        id = parse(TripleEmbed, "3.P5000.X200")
        @test id.x isa EmbTiny
        @test id.y isa Emb16
        @test id.z isa Emb8
        @test id.x.id == 3
        @test id.y.id == 5000
        @test id.z.id == 200
        @test string(parse(TripleEmbed, "0.P0000.X0")) == "0.P0000.X0"
        idmax = parse(TripleEmbed, "3.P9999.X255")
        @test idmax.x.id == 3
        @test idmax.y.id == 9999
        @test idmax.z.id == 255
        check_roundtrips(TripleEmbed, ("0.P0000.X0", "3.P9999.X255", "2.P0042.X128"))
        @test_neverthrow PP.parsebytes(TripleEmbed, ::Vector{UInt8})
    end
    @testset "embed with optional" begin
        iddef = :(@defpacked EmbedOpt (:main(embed(Emb16)),
                   optional("-", :extra(embed(Emb8)))))
        @test parsebytes_complexity(iddef) == (branches=4:6, branch_total=6, ops=11:29)
        eval(iddef)
        id = parse(EmbedOpt, "P1234-X42")
        @test id.main isa Emb16
        @test id.main.id == 1234
        @test id.extra isa Emb8
        @test id.extra.id == 42
        id2 = parse(EmbedOpt, "P1234")
        @test id2.main.id == 1234
        @test id2.extra === nothing
        @test parse(EmbedOpt, "P1234-X42") != parse(EmbedOpt, "P1234")
        check_roundtrips(EmbedOpt, ("P0000", "P9999", "P0042-X0", "P0042-X255"))
        @test_neverthrow PP.parsebytes(EmbedOpt, ::Vector{UInt8})
    end
    @testset "constructor" begin
        @test EmbedTinyOuter(parse(EmbTiny, "2"), 50) == parse(EmbedTinyOuter, "T-2-50")
        @test EmbedTinyOuter(parse(EmbTiny, "2"), 50).inner == parse(EmbTiny, "2")
        @test EmbedTinyOuter(parse(EmbTiny, "2"), 50).extra == 50
        @test MultiEmbed(parse(Emb16, "P0042"), parse(Emb8, "X7")) ==
              parse(MultiEmbed, "P0042-X7")
        for input in ("T-0-0", "T-3-99", "T-1-50")
            id = parse(EmbedTinyOuter, input)
            @test EmbedTinyOuter(id.inner, id.extra) == id
        end
        for input in ("P0000-X0", "P9999-X255")
            id = parse(MultiEmbed, input)
            @test MultiEmbed(id.a, id.b) == id
        end
    end
    @testset "show form" begin
        id = parse(Embed8Outer, "E-X42-7")
        shown = sprint(show, id)
        @test startswith(shown, "Embed8Outer(")
        @test endswith(shown, ")")
        @test occursin("Emb8", shown) || occursin("42", shown)
        @test eval(Meta.parse(repr(id))) == id
    end
    @testset "error: non-primitive type" begin
        err = try eval(:(@defpacked BadEmbed :x(embed(AbstractPacked)))); nothing
              catch e; e end
        @test err isa LoadError && err.error isa ArgumentError
    end
end # embed

@testset "Case folding" begin
    iddef = :(@defpacked CaseFolded2 ("Pfx:", :id(digits(max=999))))
    @test parsebytes_complexity(iddef) == (branches=3:3, branch_total=3, ops=36:36)
    eval(iddef)
    expr = packed_deftype(@__MODULE__, :CaseSensitive2,
                          :(("Pfx:", :id(digits(max=999))));
                          casefold=false)
    eval(expr)
    @testset "Default: case-insensitive literals" begin
        a = parse(CaseFolded2, "Pfx:42")
        b = parse(CaseFolded2, "PFX:42")
        c = parse(CaseFolded2, "pfx:42")
        @test a == b == c
    end
    @testset "casefold=false: case-sensitive literals" begin
        @test parse(CaseSensitive2, "Pfx:42") isa CaseSensitive2
        @test tryparse(CaseSensitive2, "PFX:42") === nothing
        @test tryparse(CaseSensitive2, "pfx:42") === nothing
    end
    @test_neverthrow PP.parsebytes(CaseFolded2, ::Vector{UInt8})
    @test_neverthrow PP.parsebytes(CaseSensitive2, ::Vector{UInt8})
end

@testset "show constructor form" begin
    @testset "Simple digits" begin
        id = parse(SimpleNum, "SN42")
        @test sprint(show, id) == "SimpleNum(42)"
    end
    @testset "Multi-field" begin
        id = parse(LargeId, "100-200")
        shown = sprint(show, id)
        @test startswith(shown, "LargeId(")
        @test endswith(shown, ")")
        id2 = eval(Meta.parse(shown))
        @test id == id2
    end
    @testset "Optional (present)" begin
        id = parse(WithOptional, "42.v3")
        shown = sprint(show, id)
        @test startswith(shown, "WithOptional(")
        @test endswith(shown, ")")
        @test !occursin("nothing", shown)
    end
    @testset "Optional (absent)" begin
        id = parse(WithOptional, "42")
        shown = sprint(show, id)
        @test occursin("nothing", shown)
        @test startswith(shown, "WithOptional(")
    end
    @testset "Nested optional" begin
        id = parse(DoubleOptional, "100.v2.p500")
        shown = sprint(show, id)
        @test startswith(shown, "DoubleOptional(")
        id2 = parse(DoubleOptional, "100")
        shown2 = sprint(show, id2)
        @test count("nothing", shown2) == 2
    end
    @testset "Choice" begin
        id = parse(ChoiceField, "B-99")
        @test sprint(show, id) == "ChoiceField(:B, 99)"
    end
    @testset "Charseq" begin
        id = parse(LettersFolded, "R-HSA-42")
        shown = sprint(show, id)
        @test startswith(shown, "LettersFolded(")
        @test occursin("\"HSA\"", shown)
    end
    @testset "Multi-node field" begin
        id = parse(MultiFieldProp, "v3.7")
        shown = sprint(show, id)
        @test startswith(shown, "MultiFieldProp(")
        @test occursin("3", shown) && occursin("7", shown)
    end
    @testset "eval roundtrip" begin
        for (T, input) in [
            (SimpleNum, "SN42"),
            (ChoiceField, "B-99"),
            (WithOptional, "42.v3"),
            (WithOptional, "42"),
            (DoubleOptional, "100.v2.p500"),
            (DoubleOptional, "100"),
        ]
            id = parse(T, input)
            @test eval(Meta.parse(repr(id))) == id
        end
    end
end

@testset "Equality and hashing" begin
    @testset "Usable as Dict keys" begin
        d = Dict{SimpleNum, Int}()
        id = parse(SimpleNum, "SN5")
        d[id] = 1
        @test d[parse(SimpleNum, "SN5")] == 1
    end
    @testset "Usable in Sets" begin
        s = Set{WithOptional}()
        push!(s, parse(WithOptional, "1"))
        push!(s, parse(WithOptional, "1.v0"))
        push!(s, parse(WithOptional, "1"))  # duplicate
        @test length(s) == 2
    end
end

@testset "constructor" begin
    @testset "Simple digits" begin
        @test SimpleNum(42) == parse(SimpleNum, "SN42")
        @test SimpleNum(42).id == 42
        @test SimpleNum(0).id == 0
        @test SimpleNum(9999).id == 9999
        @test string(SimpleNum(42)) == "SN0042"
        @test_throws ArgumentError SimpleNum(10000)
        @test_throws ArgumentError SimpleNum(-1)
    end
    @testset "Ranged digits" begin
        @test Ranged(100).id == 100
        @test Ranged(255).id == 255
        @test_throws ArgumentError Ranged(99)
        @test_throws ArgumentError Ranged(256)
    end
    @testset "Multi-field digits" begin
        @test LargeId(100, 200) == parse(LargeId, "100-200")
        @test LargeId(100, 200).a == 100
        @test LargeId(100, 200).b == 200
        @test Compound(3, 14) == parse(Compound, "ID:3.14")
        @test Compound(3, 14).major == 3
        @test Compound(3, 14).minor == 14
    end
    @testset "Multi-node field" begin
        id = MultiFieldProp(3, 7)
        @test id.compound == "v3.7"
        @test id == parse(MultiFieldProp, "v3.7")
    end
    @testset "Choice" begin
        @test ChoiceField(:B, 99) == parse(ChoiceField, "B-99")
        @test ChoiceField(:A, 1).kind == :A
        @test ChoiceField(:C, 0).kind == :C
        @test_throws ArgumentError ChoiceField(:D, 99)
        @test_throws ArgumentError ChoiceField(:Z, 0)
    end
    @testset "Optional" begin
        @test WithOptional(42, 3) == parse(WithOptional, "42.v3")
        @test WithOptional(42, nothing) == parse(WithOptional, "42")
        @test WithOptional(42, 3).version == 3
        @test WithOptional(42, nothing).version === nothing
        @test_throws ArgumentError WithOptional(42, 256)
    end
    @testset "Nested optional" begin
        @test DoubleOptional(100, 2, 500) == parse(DoubleOptional, "100.v2.p500")
        @test DoubleOptional(100, 2, nothing) == parse(DoubleOptional, "100.v2")
        @test DoubleOptional(100, nothing, nothing) == parse(DoubleOptional, "100")
        @test DoubleOptional(100, 2, 500).version == 2
        @test DoubleOptional(100, 2, 500).patch == 500
        @test DoubleOptional(100, nothing, nothing).version === nothing
        @test DoubleOptional(100, nothing, nothing).patch === nothing
        @test_throws ArgumentError DoubleOptional(100, nothing, 500)
    end
    @testset "Charseq" begin
        @test LettersFolded("HSA", 42) == parse(LettersFolded, "R-HSA-42")
        @test LettersFolded("HSA", 42).code == "HSA"
        @test LettersFolded("hsa", 42) == LettersFolded("HSA", 42)  # casefold
        @test_throws ArgumentError LettersFolded("H1A", 42)  # invalid char
        @test_throws ArgumentError LettersFolded("HS", 42)   # too short
    end
    @testset "Optional charseq" begin
        @test OptLettersFixed(42, "AB") == parse(OptLettersFixed, "42-AB")
        @test OptLettersFixed(42, nothing) == parse(OptLettersFixed, "42")
        @test OptLettersFixed(42, "AB").suffix == "AB"
        @test OptLettersFixed(42, nothing).suffix === nothing
        @test_throws ArgumentError OptLettersFixed(42, "A")   # too short
        @test_throws ArgumentError OptLettersFixed(42, "ABC") # too long
    end
    @testset "Round-trip invariant" begin
        for (T, inputs) in [
            (SimpleNum, ("SN42", "SN0", "SN9999")),
            (Ranged, ("100", "200", "255")),
            (LargeId, ("100-200", "0-0", "65535-65535")),
            (Compound, ("ID:3.14", "ID:0.0", "ID:99.99")),
            (ChoiceField, ("A-0", "B-999", "C-42")),
            (LettersFolded, ("R-HSA-42", "R-ABC-0")),
        ]
            for input in inputs
                id = parse(T, input)
                props = map(p -> getproperty(id, p), propertynames(id))
                @test T(props...) == id
            end
        end
        # Multi-node field: constructor takes individual components, not the combined string
        for (v1, v2) in ((3, 7), (0, 0), (9, 9))
            @test parse(MultiFieldProp, string(MultiFieldProp(v1, v2))) == MultiFieldProp(v1, v2)
        end
        # Optional types: explicit round-trip through properties
        for input in ("42.v3", "42")
            id = parse(WithOptional, input)
            @test WithOptional(id.id, id.version) == id
        end
        for input in ("100.v2.p500", "100.v2", "100")
            id = parse(DoubleOptional, input)
            @test DoubleOptional(id.id, id.version, id.patch) == id
        end
        for input in ("42-AB", "42")
            id = parse(OptLettersFixed, input)
            @test OptLettersFixed(id.id, id.suffix) == id
        end
    end
end

@testset "structured choice" begin
    @testset "two-arm basic" begin
        iddef = :(@defpacked StructChoice1 (:id(choice(("A", digits(2, pad=2)), ("B", digits(3, pad=3))))))
        @test parsebytes_complexity(iddef) == (branches=5:13, branch_total=13, ops=2:62)
        eval(iddef)
        @test string(parse(StructChoice1, "A42")) == "A42"
        @test string(parse(StructChoice1, "B007")) == "B007"
        @test tryparse(StructChoice1, "C99") === nothing
        @test tryparse(StructChoice1, "A") === nothing
        check_roundtrips(StructChoice1, ("A00", "A99", "B000", "B999"))
    end
    @testset "two-arm with fields" begin
        iddef = :(@defpacked StructChoice2 (choice(:a(digits(2, pad=2)), ("X", :b(digits(3, pad=3))))))
        @test parsebytes_complexity(iddef) == (branches=5:12, branch_total=12, ops=2:60)
        eval(iddef)
        @test parse(StructChoice2, "42").a == 42
        @test parse(StructChoice2, "42").b === nothing
        @test parse(StructChoice2, "X007").b == 7
        @test parse(StructChoice2, "X007").a === nothing
        check_roundtrips(StructChoice2, ("00", "99", "X000", "X999"))
    end
    @testset "with empty arm" begin
        iddef = :(@defpacked StructChoiceOpt (choice(("A", :x(digits(2, pad=2))), ("B", :y(digits(3, pad=3))), "")))
        @test parsebytes_complexity(iddef) == (branches=2:10, branch_total=10, ops=3:65)
        eval(iddef)
        @test parse(StructChoiceOpt, "A42").x == 42
        @test parse(StructChoiceOpt, "A42").y === nothing
        @test parse(StructChoiceOpt, "B007").y == 7
        @test parse(StructChoiceOpt, "B007").x === nothing
        @test tryparse(StructChoiceOpt, "C99") === nothing
    end
    @testset "letter-range dispatch" begin
        iddef = :(@defpacked LetterChoice (choice(("X", :a(digits(3, pad=3))), ("Y", :b(digits(2, pad=2))), ("Z", :c(digits(1))))))
        @test parsebytes_complexity(iddef) == (branches=5:19, branch_total=19, ops=2:83)
        eval(iddef)
        @test parse(LetterChoice, "X042").a == 42
        @test parse(LetterChoice, "Y07").b == 7
        @test parse(LetterChoice, "Z5").c == 5
        @test tryparse(LetterChoice, "W1") === nothing
        check_roundtrips(LetterChoice, ("X000", "X999", "Y00", "Y99", "Z0", "Z9"))
    end
    @testset "complex arm dispatch" begin
        iddef = :(@defpacked ComplexChoice (choice(
            (choice("O", "P", "Q"), :d1(digits(1)), :a1(alphnum(3)), :d2(digits(1))),
            (charset(1, 'A':'N', 'R':'Z'), :d3(digits(1)), :a2(alphnum(8))))))
        @test parsebytes_complexity(iddef) == (branches=5:17, branch_total=17, ops=2:75)
        eval(iddef)
        @test string(parse(ComplexChoice, "P3ABC5")) == "P3ABC5"
        @test string(parse(ComplexChoice, "A1ABCDEFGH")) == "A1ABCDEFGH"
        @test tryparse(ComplexChoice, "O") === nothing
        @test tryparse(ComplexChoice, "") === nothing
        check_roundtrips(ComplexChoice, ("O0AAA0", "Q9ZZZ9", "A0AAAAAAAA", "N9ZZZZZZZZ"))
    end
    @testset "casefold dispatch" begin
        iddef = :(@defpacked CaseFoldChoice (choice(("ab", :x(digits(2, pad=2))), ("cd", :y(digits(2, pad=2))))))
        @test parsebytes_complexity(iddef) == (branches=5:13, branch_total=13, ops=2:57)
        eval(iddef)
        @test parse(CaseFoldChoice, "ab42").x == 42
        @test parse(CaseFoldChoice, "AB42").x == 42
        @test parse(CaseFoldChoice, "cd07").y == 7
        @test parse(CaseFoldChoice, "CD07").y == 7
        @test tryparse(CaseFoldChoice, "ef01") === nothing
        check_roundtrips(CaseFoldChoice, ("ab00", "ab99", "cd00", "cd99"))
    end
    @testset "cascade fallback" begin
        iddef = :(@defpacked CascadeChoice (choice((:a(digits(2, pad=2)), "X"), (:b(digits(2, pad=2)), "Y"))))
        @test parsebytes_complexity(iddef) == (branches=5:13, branch_total=13, ops=2:58)
        eval(iddef)
        @test parse(CascadeChoice, "42X").a == 42
        @test parse(CascadeChoice, "42X").b === nothing
        @test parse(CascadeChoice, "07Y").b == 7
        @test parse(CascadeChoice, "07Y").a === nothing
        @test tryparse(CascadeChoice, "42Z") === nothing
        check_roundtrips(CascadeChoice, ("00X", "99X", "00Y", "99Y"))
    end
    @testset "multi-byte window dispatch" begin
        iddef = :(@defpacked MultiByteChoice (choice(("AX", :x(digits(2, pad=2))), ("AY", :y(digits(2, pad=2))))))
        @test parsebytes_complexity(iddef) == (branches=5:13, branch_total=13, ops=2:58)
        eval(iddef)
        @test parse(MultiByteChoice, "AX42").x == 42
        @test parse(MultiByteChoice, "AX42").y === nothing
        @test parse(MultiByteChoice, "AY07").y == 7
        @test parse(MultiByteChoice, "AY07").x === nothing
        @test tryparse(MultiByteChoice, "AZ01") === nothing
        check_roundtrips(MultiByteChoice, ("AX00", "AX99", "AY00", "AY99"))
    end
    @testset "four arms" begin
        iddef = :(@defpacked FourArm (choice(
            ("A", :a(digits(2, pad=2))), ("B", :b(digits(2, pad=2))),
            ("C", :c(digits(2, pad=2))), ("D", :d(digits(2, pad=2))))))
        @test parsebytes_complexity(iddef) == (branches=5:25, branch_total=25, ops=2:111)
        eval(iddef)
        @test parse(FourArm, "A42").a == 42
        @test parse(FourArm, "B07").b == 7
        @test parse(FourArm, "C99").c == 99
        @test parse(FourArm, "D00").d == 0
        @test parse(FourArm, "A42").b === nothing
        @test tryparse(FourArm, "E01") === nothing
        check_roundtrips(FourArm, ("A00", "B00", "C00", "D00", "A99", "D99"))
    end
    @testset "digit vs letter discrimination" begin
        iddef = :(@defpacked DigitLetterChoice (choice((:n(digits(3, pad=3))), (letters(1), :m(digits(2, pad=2))))))
        @test parsebytes_complexity(iddef) == (branches=5:12, branch_total=12, ops=2:68)
        eval(iddef)
        @test parse(DigitLetterChoice, "042").n == 42
        @test parse(DigitLetterChoice, "042").m === nothing
        @test parse(DigitLetterChoice, "A07").m == 7
        @test parse(DigitLetterChoice, "A07").n === nothing
        check_roundtrips(DigitLetterChoice, ("000", "999", "A00", "Z99"))
    end
    @testset "empty arm with dispatch" begin
        iddef = :(@defpacked DispatchOpt (choice(("X", :x(digits(2, pad=2))), ("Y", :y(digits(2, pad=2))), "")))
        @test parsebytes_complexity(iddef) == (branches=2:10, branch_total=10, ops=3:60)
        eval(iddef)
        @test parse(DispatchOpt, "X42").x == 42
        @test parse(DispatchOpt, "Y07").y == 7
        @test tryparse(DispatchOpt, "Z01") === nothing
        @test string(tryparse(DispatchOpt, "")) == ""
        check_roundtrips(DispatchOpt, ("X00", "X99", "Y00", "Y99"))
    end
    @testset "field wrapping structured choice" begin
        iddef = :(@defpacked FieldChoice (:id(choice(("A", digits(2, pad=2)), ("B", digits(3, pad=3))))))
        @test parsebytes_complexity(iddef) == (branches=5:13, branch_total=13, ops=2:62)
        eval(iddef)
        @test parse(FieldChoice, "A42").id == "A42"
        @test parse(FieldChoice, "B007").id == "B007"
        @test propertynames(parse(FieldChoice, "A42")) == (:id,)
        check_roundtrips(FieldChoice, ("A00", "A99", "B000", "B999"))
    end
    @testset "string choice inside arm" begin
        iddef = :(@defpacked InnerChoice (choice((:tag(choice("alpha", "beta")), :n(digits(1))), ("X", :m(digits(2, pad=2))))))
        @test parsebytes_complexity(iddef) == (branches=5:18, branch_total=18, ops=2:63)
        eval(iddef)
        @test parse(InnerChoice, "alpha3").tag == :alpha
        @test parse(InnerChoice, "beta5").tag == :beta
        @test parse(InnerChoice, "alpha3").n == 3
        @test parse(InnerChoice, "X07").m == 7
        @test parse(InnerChoice, "X07").tag === nothing
        check_roundtrips(InnerChoice, ("alpha0", "beta9", "X00", "X99"))
    end
    @testset "optional inside arm" begin
        iddef = :(@defpacked OptInArm (choice(("A", :x(digits(2, pad=2)), optional("-", :y(digits(1)))), ("B", :z(digits(2, pad=2))))))
        @test parsebytes_complexity(iddef) == (branches=5:18, branch_total=18, ops=2:73)
        eval(iddef)
        @test parse(OptInArm, "A42").x == 42
        @test parse(OptInArm, "A42").y === nothing
        @test parse(OptInArm, "A42-5").y == 5
        @test parse(OptInArm, "B07").z == 7
        @test parse(OptInArm, "B07").x === nothing
        check_roundtrips(OptInArm, ("A00", "A99-0", "A42-5", "B00", "B99"))
    end
    @testset "variable-length arms" begin
        iddef = :(@defpacked VarArms (choice(("A", :x(digits(1:3))), ("B", :y(digits(2:4, pad=2))))))
        @test parsebytes_complexity(iddef) == (branches=5:23, branch_total=23, ops=2:115)
        eval(iddef)
        @test parse(VarArms, "A1").x == 1
        @test parse(VarArms, "A123").x == 123
        @test parse(VarArms, "B02").y == 2
        @test parse(VarArms, "B1234").y == 1234
        @test tryparse(VarArms, "A") === nothing
        @test tryparse(VarArms, "B1") === nothing
        check_roundtrips(VarArms, ("A1", "A99", "A999", "B02", "B99", "B0099", "B9999"))
    end
    @testset "cross-alternative dispatch" begin
        iddef = :(@defpacked CrossAlt (choice((choice("AB", "CD"), :x(digits(1))), (choice("AD", "CB"), :y(digits(1))))))
        @test parsebytes_complexity(iddef) == (branches=5:17, branch_total=17, ops=2:67)
        eval(iddef)
        @test parse(CrossAlt, "AB3").x == 3
        @test parse(CrossAlt, "CD7").x == 7
        @test parse(CrossAlt, "AD5").y == 5
        @test parse(CrossAlt, "CB9").y == 9
        @test parse(CrossAlt, "AB3").y === nothing
        @test parse(CrossAlt, "AD5").x === nothing
        check_roundtrips(CrossAlt, ("AB0", "CD9", "AD0", "CB9"))
    end
    @testset "nested: structured choice inside optional" begin
        iddef = :(@defpacked ChoiceInOpt (:id(digits(max=99)),
            optional("-", choice(("A", :x(digits(2, pad=2))), ("B", :y(digits(2, pad=2)))))))
        @test parsebytes_complexity(iddef) == (branches=6:24, branch_total=24, ops=20:101)
        eval(iddef)
        bare = parse(ChoiceInOpt, "42")
        @test bare.id == 42
        @test bare.x === nothing
        @test bare.y === nothing
        ax = parse(ChoiceInOpt, "42-A07")
        @test ax.id == 42
        @test ax.x == 7
        @test ax.y === nothing
        by = parse(ChoiceInOpt, "42-B99")
        @test by.y == 99
        @test by.x === nothing
        check_roundtrips(ChoiceInOpt, ("42", "0-A00", "99-B99"))
    end
end

end # @testset "PackedParselets"
